def solve(sx: int, sy: int, tx: int, ty: int) -> int:
    count = 0
    while tx > sx or ty > sy:
        if tx == sx and ty == sy:
            return count
        if tx > ty:
            if ty < sy:
                return -1
            # Subtract the maximum possible multiples of ty from tx
            delta = max(1, (tx - sx) // ty)
            tx -= delta * ty
            count += delta
        else:
            if tx < sx:
                return -1
            # Subtract the maximum possible multiples of tx from ty
            delta = max(1, (ty - sy) // tx)
            ty -= delta * tx
            count += delta
    return count if tx == sx and ty == sy else -1
